set -euo pipefail
file=/doc/README.md
if [ ! -f "$file" ]; then echo "File not found: $file" >&2; exit 1; fi
awk '
BEGIN { first_heading_seen=0; toc_count=0 }
function trim(s){ sub(/^[[:space:]]+/,"",s); sub(/[[:space:]]+$/,"",s); return s }
function anchorize(s, t){ t=tolower(s); gsub(/ /,"-",t); return t }
{
  lines[NR]=$0
  if ($0 ~ /^#{1,2} /) {
    level = match($0, /^## /) ? 2 : 1
    text = $0
    sub(/^#{1,2} /, "", text)
    headings[++toc_count] = sprintf("%s- [%s](#%s)", level==2 ? "  " : "", text, anchorize(text))
    if (!first_heading_seen) first_heading_nr=NR
    first_heading_seen=1
  }
}
END {
  if (!first_heading_seen) {
    for (i=1;i<=NR;i++) print lines[i]
    exit
  }
  for (i=1;i<=NR;i++) {
    print lines[i]
    if (i==first_heading_nr) {
      print ""
      for (j=1;j<=toc_count;j++) print headings[j]
    }
  }
}
' "$file" > "$file.tmp"
mv "$file.tmp" "$file"

