# Parse deps and produce a topological order with awk
order=$(awk '
function trim(s){ sub(/^[ \t]+/, "", s); sub(/[ \t]+$/, "", s); return s }
{
  line=$0
  if (line ~ /^[ \t]*$/) next
  split(line, parts, ":")
  t=trim(parts[1])
  targets[t]=1
  rest=""
  if (length(parts) > 1) rest=trim(parts[2])
  depcount[t]=0
  if (rest != "") {
    n=split(rest, deps, /[ \t]+/)
    for (i=1;i<=n;i++) if (deps[i] != "") {
      d=deps[i]
      deps_of[t, ++depcount[t]] = d
      nodes[d]=1
      nodes[t]=1
    }
  } else {
    nodes[t]=1
  }
}
END {
  for (n in nodes) { indeg[n]=0; revcount[n]=0 }
  for (t in nodes) {
    for (i=1;i<=depcount[t];i++) {
      d=deps_of[t,i]
      indeg[t]++
      rev[d, ++revcount[d]] = t
    }
  }
  while (1) {
    found=""
    for (n in nodes) {
      if (!done[n] && indeg[n]==0) {
        if (found=="" || n < found) found=n
      }
    }
    if (found=="") break
    done[found]=1
    out[++outn]=found
    for (i=1;i<=revcount[found];i++) {
      m=rev[found,i]
      indeg[m]--
    }
  }
  count=0
  for (n in nodes) count++
  if (outn != count) {
    print "cycle detected" > "/dev/stderr"
    exit 1
  }
  for (i=1;i<=outn;i++) print out[i]
}
